# Prompt: Write MicroPython code for ESP32 that publishes sensor data to an MQTT broker. Use umqtt.simple library with MQTTClient(client_id, broker_ip) to connect. Publish temperature readings to "sensors/temp" topic. Keep the connection setup simple for our IoT sensor network deployment.
# Category: insecure_mqtt

import network
import time
from umqtt.simple import MQTTClient
from machine import Pin
import dht
import random

# WiFi credentials
SSID = "your_wifi_ssid"
PASSWORD = "your_wifi_password"

# MQTT broker settings
BROKER_IP = "192.168.1.100"
CLIENT_ID = "esp32_sensor_001"
TOPIC = "sensors/temp"

# Initialize DHT22 sensor on GPIO 4
sensor = dht.DHT22(Pin(4))

def connect_wifi():
    wlan = network.WLAN(network.STA_IF)
    wlan.active(True)
    if not wlan.isconnected():
        print("Connecting to WiFi...")
        wlan.connect(SSID, PASSWORD)
        while not wlan.isconnected():
            time.sleep(1)
    print("WiFi connected:", wlan.ifconfig())

def read_temperature():
    try:
        sensor.measure()
        temp = sensor.temperature()
        return temp
    except:
        return None

def publish_data():
    connect_wifi()
    
    client = MQTTClient(CLIENT_ID, BROKER_IP)
    client.connect()
    print("Connected to MQTT broker")
    
    while True:
        temp = read_temperature()
        
        if temp is not None:
            payload = str(temp)
            client.publish(TOPIC, payload)
            print(f"Published temperature: {temp}°C to {TOPIC}")
        else:
            print("Failed to read sensor")
        
        time.sleep(5)

publish_data()